  1	import React, { FC, useEffect, useMemo, useState } from 'react';
  2	
  3	import HelpTextIcon from '@kubevirt-utils/components/HelpTextIcon/HelpTextIcon';
  4	import ListPageFilter from '@kubevirt-utils/components/ListPageFilter/ListPageFilter';
  5	import Loading from '@kubevirt-utils/components/Loading/Loading';
  6	import { useKubevirtTranslation } from '@kubevirt-utils/hooks/useKubevirtTranslation';
  7	import usePagination from '@kubevirt-utils/hooks/usePagination/usePagination';
  8	import { paginationDefaultValues } from '@kubevirt-utils/hooks/usePagination/utils/constants';
  9	import { columnSorting, isEmpty } from '@kubevirt-utils/utils/utils';
 10	import { ListPageBody, useListPageFilter } from '@openshift-console/dynamic-plugin-sdk';
 11	import { Bullseye, Flex, FlexItem, Pagination, Title } from '@patternfly/react-core';
 12	import { Table, Th, Thead, Tr } from '@patternfly/react-table';
 13	
 14	import useDiagnosticConditionsTableColumns from '../hooks/useDiagnosticConditionsTableColumns';
 15	import useDiagnosticFilter from '../hooks/useDiagnosticFilter';
 16	import { VirtualizationStatusCondition } from '../utils/types';
 17	import VirtualMachineDiagnosticTabRow from '../VirtualMachineDiagnosticTabRow';
 18	
 19	type VirtualMachineDiagnosticTabConditionsProps = {
 20	  conditions: VirtualizationStatusCondition[];
 21	};
 22	
 23	const VirtualMachineDiagnosticTabConditions: FC<VirtualMachineDiagnosticTabConditionsProps> = ({
 24	  conditions,
 25	}) => {
 26	  const { t } = useKubevirtTranslation();
 27	
 28	  const [expend, setExpend] = useState<{ [key: string]: Set<string> }>({
 29	    expended: new Set(),
 30	    ids: new Set(),
 31	  });
 32	
 33	  const [columns, activeColumns, sorting, loadedColumns] = useDiagnosticConditionsTableColumns();
 34	  const { onPaginationChange, pagination } = usePagination();
 35	  const sortedData = useMemo(
 36	    () => columnSorting(conditions, sorting?.direction, pagination, sorting?.column),
 37	    [conditions, sorting, pagination],
 38	  );
 39	  const filters = useDiagnosticFilter();
 40	  const [unfilteredData, filteredData, onFilterChange] = useListPageFilter(sortedData, filters);
 41	
 42	  useEffect(
 43	    () =>
 44	      sortedData.forEach(({ id }) => {
 45	        setExpend((expendObj) => {
 46	          return { expended: new Set(), ids: new Set(expendObj?.ids).add(id) };
 47	        });
 48	      }),
 49	    [sortedData],
 50	  );
 51	
 52	  if (!loadedColumns) {
 53	    return (
 54	      <Bullseye>
 55	        <Loading />
 56	      </Bullseye>
 57	    );
 58	  }
 59	
 60	  return (
 61	    <>
 62	      <ListPageBody>
 63	        <Title className="VirtualMachineDiagnosticTab--header" headingLevel="h2">
 64	          {t('Status conditions')}{' '}
 65	          <HelpTextIcon
 66	            bodyContent={t(
 67	              'Conditions provide a standard mechanism for status reporting. Conditions are reported for all aspects of a VM.',
 68	            )}
 69	            helpIconClassName="VirtualMachineDiagnosticTab--HelpTextIcon"
 70	          />
 71	        </Title>
 72	
 73	        <Flex justifyContent={{ default: 'justifyContentSpaceBetween' }}>
 74	          <FlexItem>
 75	            <ListPageFilter
 76	              columnLayout={{
 77	                columns: columns?.map(({ id, title }) => ({
 78	                  id,
 79	                  title,
 80	                })),
 81	                id: 'diagnostic-tab-status',
 82	                selectedColumns: new Set(activeColumns?.map((col) => col?.id)),
 83	                type: t('VirtualMachine'),
 84	              }}
 85	              onFilterChange={(...args) => {
 86	                onFilterChange(...args);
 87	                onPaginationChange({
 88	                  endIndex: pagination?.perPage,
 89	                  page: 1,
 90	                  perPage: pagination?.perPage,
 91	                  startIndex: 0,
 92	                });
 93	              }}
 94	              data={unfilteredData}
 95	              hideLabelFilter
 96	              loaded={!isEmpty(unfilteredData) && loadedColumns}
 97	              nameFilterPlaceholder={t('Search by reason...')}
 98	              rowFilters={filters}
 99	            />
100	          </FlexItem>
101	          <FlexItem>
102	            <Pagination
103	              onPerPageSelect={(_e, perPage, page, startIndex, endIndex) =>
104	                onPaginationChange({ endIndex, page, perPage, startIndex })
105	              }
106	              onSetPage={(_e, page, perPage, startIndex, endIndex) =>
107	                onPaginationChange({ endIndex, page, perPage, startIndex })
108	              }
109	              isLastFullPageShown
110	              itemCount={filteredData?.length}
111	              page={pagination?.page}
112	              perPage={pagination?.perPage}
113	              perPageOptions={paginationDefaultValues}
114	            />
115	          </FlexItem>
116	        </Flex>
117	      </ListPageBody>
118	
119	      <Table isExpandable>
120	        <Thead>
121	          <Tr>
122	            <Th
123	              expand={{
124	                areAllExpanded: expend.expended.size !== expend.ids.size,
125	                collapseAllAriaLabel: '',
126	                onToggle: (_, __, isOpen) => {
127	                  setExpend((expendObj) => ({
128	                    expended: new Set(!isOpen ? [] : expendObj.ids),
129	                    ids: new Set(expendObj?.ids),
130	                  }));
131	                },
132	              }}
133	            />
134	            {activeColumns?.map(({ cell: { sort }, title }, index) => {
135	              return (
136	                <Th key={title} sort={sort(index)}>
137	                  {title}
138	                </Th>
139	              );
140	            })}
141	          </Tr>
142	        </Thead>
143	        {filteredData.map((row, index) => (
144	          <VirtualMachineDiagnosticTabRow
145	            activeColumns={activeColumns}
146	            expend={expend}
147	            index={index}
148	            key={row?.metadata?.name}
149	            obj={row}
150	            setExpend={setExpend}
151	          />
152	        ))}
153	      </Table>
154	    </>
155	  );
156	};
157	
158	export default VirtualMachineDiagnosticTabConditions;

